import { useState } from "react";
import { useAuth } from "../AuthContext";   // ✅ use your AuthContext

function Register({ setSuccessMessage }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState(""); // just for form (not stored)
  const { login } = useAuth();

  const handleSubmit = (e) => {
    e.preventDefault();
    // Here you can add API call later
    login(username);  // auto-login after register
    setSuccessMessage("✅ Registered & Logged in successfully!");
  };

  return (
    <div>
      <h2>Register</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Enter username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />
        <input
          type="password"
          placeholder="Enter password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button type="submit">Register</button>
      </form>
    </div>
  );
}

export default Register;
